(alter-meta! (resolve 'clojure.core/drop-last) fill {:arglists (quote ([coll] [n coll])), :doc "Return a lazy sequence of all but the last n (default 1) items in coll"})
(alter-meta! (resolve 'clojure.core/drop-while) fill {:arglists (quote ([pred] [pred coll])), :doc "Returns a lazy sequence of the items in coll starting from the\n  first item for which (pred item) returns logical false.  Returns a\n  stateful transducer when no collection is provided."})
