(alter-meta! (resolve 'clojure.core/max-key) fill {:arglists (quote ([k x] [k x y] [k x y & more])), :doc "Returns the x for which (k x), a number, is greatest.\n\n  If there are multiple such xs, the last one is returned."})
(alter-meta! (resolve 'clojure.core/memfn) fill {:arglists (quote ([name & args])), :doc "Expands into code that creates a fn that expects to be passed an\n  object and any args and calls the named instance method on the\n  object passing the args. Use when you want to treat a Java method as\n  a first-class fn. name may be type-hinted with the method receiver's\n  type in order to avoid reflective calls."})
